__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* wall,
    __global int* src,
    __global int* dst,
    const int cols,
    const int rows,
    const int t,
    const int borderCols,
    const int theHalo,
    __local int* localSrc1,
    __local int* localSrc2,
    __global int* outputBuffer)
{
    int n = get_global_id(0);
    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Each work-item processes one column index n
    // We process pyramid_height steps in this kernel invocation

    // We need to process from t to t + pyramid_height - 1 rows

    // Load initial src data into local memory for halo access
    // localSrc1 and localSrc2 are local buffers for double buffering

    // Compute the index in src/dst arrays for current n
    // src and dst are arrays of length cols

    // We will iterate pyramid_height times, updating dst from src

    // For boundary conditions, we clamp indices

    // Initialize localSrc1 with src[n]
    if (n < cols) {
        localSrc1[local_id] = src[n];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < pyramid_height; i++) {
        int row = t + i + 1;
        if (row >= rows) break;

        int min_val = localSrc1[local_id];
        if (local_id > 0)
            min_val = min(min_val, localSrc1[local_id - 1]);
        if (local_id < local_size - 1 && (n + 1) < cols)
            min_val = min(min_val, localSrc1[local_id + 1]);

        int wall_val = wall[row * cols + n];
        int new_val = wall_val + min_val;

        localSrc2[local_id] = new_val;

        barrier(CLK_LOCAL_MEM_FENCE);

        // Swap localSrc1 and localSrc2 pointers by copying
        int temp = localSrc1[local_id];
        localSrc1[local_id] = localSrc2[local_id];
        localSrc2[local_id] = temp;

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write final result to dst
    if (n < cols) {
        dst[n] = localSrc1[local_id];
    }
}
